        }
        input:checked + .slider {
            background-color: #ff8a00;
        }
        input:checked + .slider:before {
            transform: translateX(20px);
        }
    </style>

    <!-- Import map for Three.js -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js",
                "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/"
            }
        }
    </script>
</head>
<body>
    <div id="ui-card">
        <h1>GARGANTUA</h1>
        <p><b>Left Click:</b> Rotate</p>
        <p><b>Right Click:</b> Pan</p>
        <p><b>Scroll:</b> Zoom (1.5 - 60.0)</p>

        <div class="toggle-container">
            <label class="toggle-switch">
                <input type="checkbox" id="anim-toggle" checked>
                <span class="slider"></span>
            </label>
            <span style="font-size: 14px;">Animation</span>
        </div>
    </div>

    <!-- Vertex Shader -->
    <script type="x-shader/x-vertex" id="vertexShader">
        precision highp float;
        varying vec2 vUv;
        void main() {
            vUv = uv;
            gl_Position = vec4(position, 1.0);
        }
    </script>

    <!-- Fragment Shader -->
    <script type="x-shader/x-fragment" id="fragmentShader">
        precision highp float;

        varying vec2 vUv;

        uniform float iTime;
        uniform vec2 iResolution;
        uniform vec3 iCameraPos;
        uniform vec3 iCameraDir;
        uniform vec3 iCameraUp;
        uniform float iFov;

        // Key physical parameters - easy to tweak
        uniform float uBhRadius;    // default 1.0
        uniform float uDiskInner;   // default 3.0
        uniform float uDiskOuter;   // default 10.0

        #define MAX_STEPS 150
        #define PI 3.14159265359

        // Hash function for starfield
        float hash(float n) { return fract(sin(n) * 1e4); }
        float hash(vec2 p) { return fract(1e4 * sin(17.0 * p.x + p.y * 0.1) * (0.1 + abs(sin(p.y * 13.0 + p.x)))); }

        // 3D noise for procedural starfield & accretion disk texture
        float noise(vec3 x) {
            const vec3 step = vec3(110, 241, 171);
            vec3 i = floor(x);
            vec3 f = fract(x);
            float n = dot(i, step);
            vec3 u = f * f * (3.0 - 2.0 * f);
            return mix(mix(mix( hash(n + dot(step, vec3(0, 0, 0))), hash(n + dot(step, vec3(1, 0, 0))), u.x),
                           mix( hash(n + dot(step, vec3(0, 1, 0))), hash(n + dot(step, vec3(1, 1, 0))), u.x), u.y),
                       mix(mix( hash(n + dot(step, vec3(0, 0, 1))), hash(n + dot(step, vec3(1, 0, 1))), u.x),
                           mix( hash(n + dot(step, vec3(0, 1, 1))), hash(n + dot(step, vec3(1, 1, 1))), u.x), u.y), u.z);
        }

        // Generate procedural starfield background
        vec3 getStarfield(vec3 dir) {
            vec3 color = vec3(0.0);

            // Base galaxy cloud noise
            float n1 = noise(dir * 5.0);
            float n2 = noise(dir * 15.0);
            vec3 cloudColor = mix(vec3(0.1, 0.2, 0.4), vec3(0.4, 0.1, 0.2), n1);
            color += cloudColor * n2 * 0.1;

            // Star points
            vec3 p = floor(dir * 200.0);
            vec3 f = fract(dir * 200.0);
            float n = hash(p.x + p.y * 113.0 + p.z * 311.0);

            if (n > 0.98) {
                // High density stars
                float starIntensity = pow(1.0 - length(f - 0.5) * 2.0, 4.0);

                // Breathing light effect
                float breathing = 0.5 + 0.5 * sin(iTime * (n * 3.0 + 1.0) + n * 10.0);

                // Star colors (Blue supergiants, red dwarfs, etc.)
                vec3 starColor;
                if (n > 0.995) starColor = vec3(0.6, 0.8, 1.0); // Blue
                else if (n > 0.99) starColor = vec3(1.0, 0.6, 0.4); // Red/Orange
                else starColor = vec3(1.0, 0.9, 0.8); // White/Yellow

                color += starColor * starIntensity * breathing * (n - 0.98) * 50.0;
            }

            return color;
        }

        void main() {
            // Protect aspect ratio calculation to prevent NaN
            float aspect = max(iResolution.x, 1.0) / max(iResolution.y, 1.0);
            vec2 uv = vUv * 2.0 - 1.0;
            uv.x *= aspect;

            // Ray construction
            vec3 camDir = normalize(iCameraDir);
            vec3 camRight = normalize(cross(camDir, iCameraUp));
            vec3 camUp = cross(camRight, camDir);

            float fovRad = iFov * PI / 180.0;
            // Protect focal length to prevent division by zero
            float focalLength = 1.0 / max(tan(fovRad * 0.5), 1e-4);

            vec3 rayDir = normalize(camRight * uv.x + camUp * uv.y + camDir * focalLength);
            vec3 rayOrigin = iCameraPos;

            // Ray marching setup
            vec3 pos = rayOrigin;
            vec3 dir = rayDir;

            vec3 colorAccum = vec3(0.0);
            float glow = 0.0;
            bool escaped = false;

            // Ray marching state
            float dt = 0.05;
            float g = 1.5 * uBhRadius; // Gravitational constant factor

            for (int i = 0; i < MAX_STEPS; i++) {
                float r = length(pos);

                // Check if absorbed by black hole
                if (r < uBhRadius * 1.05) {
                    break;
                }

                // Check if escaped to far field
                if (r > 40.0) {
                    escaped = true;
                    break;
